    allow_prefix = os.getenv("EXT_AUTHZ_ALLOW_PREFIX", "allow:")

    denied_status = int(os.getenv("EXT_AUTHZ_DENIED_STATUS", "403"))
    deny_body = os.getenv("EXT_AUTHZ_DENY_BODY", "Forbidden")

