    max_send = int(os.getenv("EXT_AUTHZ_MAX_SEND_BYTES", str(4 * 1024 * 1024)))

    server_opts = [
        ("grpc.max_receive_message_length", max_recv),
        ("grpc.max_send_message_length", max_send),
    ]

